package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;
    private Token reusableToken;

    @BeforeEach
    void setUp() throws Exception {
        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Create a CSVFormat mock or dummy (can be null if not used in nextRecord)
        CSVFormat format = mock(CSVFormat.class);

        // Instantiate CSVParser using reflection to inject the mock Lexer
        parser = new CSVParser(new StringReader(""), format);

        // Use reflection to set private final lexer field to lexerMock
        var lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, lexerMock);

        // Access reusableToken field
        var tokenField = CSVParser.class.getDeclaredField("reusableToken");
        tokenField.setAccessible(true);
        reusableToken = (Token) tokenField.get(parser);

        // Reset recordNumber to 0
        var recordNumberField = CSVParser.class.getDeclaredField("recordNumber");
        recordNumberField.setAccessible(true);
        recordNumberField.setLong(parser, 0L);

        // Clear record list
        var recordField = CSVParser.class.getDeclaredField("record");
        recordField.setAccessible(true);
        List<String> recordList = (List<String>) recordField.get(parser);
        recordList.clear();

        // Clear headerMap (can be null or empty)
        var headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);
        headerMapField.set(parser, Map.of());
    }

    @Test
    void testNextRecord_withTokensAndEORECORD() throws Exception {
        // Setup tokens to return TOKEN, TOKEN, EORECORD
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.TOKEN;
            reusableToken.content = "value1";
            reusableToken.isReady = false;
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.TOKEN;
            reusableToken.content = "value2";
            reusableToken.isReady = false;
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.EORECORD;
            reusableToken.content = "value3";
            reusableToken.isReady = false;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        // Spy on addRecordValue to add token content to record list
        Method addRecordValueMethod = CSVParser.class.getDeclaredMethod("addRecordValue");
        addRecordValueMethod.setAccessible(true);

        // We mock addRecordValue by invoking it normally since it uses record and reusableToken
        // So no need to spy, just call nextRecord and it will call addRecordValue internally.

        CSVRecord record = parser.nextRecord();

        assertNotNull(record);
        assertEquals(1, parser.getRecordNumber());
        String[] values = record.values();
        assertArrayEquals(new String[] { "value1", "value2", "value3" }, values);
        assertNull(record.getComment());
    }

    @Test
    void testNextRecord_withEOFAndIsReadyTrue() throws Exception {
        // Setup tokens: TOKEN, EOF with isReady true
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.TOKEN;
            reusableToken.content = "val1";
            reusableToken.isReady = false;
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.EOF;
            reusableToken.content = "val2";
            reusableToken.isReady = true;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        CSVRecord record = parser.nextRecord();

        assertNotNull(record);
        assertEquals(1, parser.getRecordNumber());
        String[] values = record.values();
        assertArrayEquals(new String[] { "val1", "val2" }, values);
        assertNull(record.getComment());
    }

    @Test
    void testNextRecord_withEOFAndIsReadyFalse_returnsNull() throws Exception {
        // Setup tokens: EOF with isReady false immediately
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.EOF;
            reusableToken.content = null;
            reusableToken.isReady = false;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        CSVRecord record = parser.nextRecord();

        assertNull(record);
        assertEquals(0, parser.getRecordNumber());
    }

    @Test
    void testNextRecord_withCommentTokens() throws Exception {
        // Setup tokens: COMMENT, COMMENT, EORECORD
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.COMMENT;
            reusableToken.content = "comment line 1";
            reusableToken.isReady = false;
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.COMMENT;
            reusableToken.content = "comment line 2";
            reusableToken.isReady = false;
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.EORECORD;
            reusableToken.content = "value1";
            reusableToken.isReady = false;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        CSVRecord record = parser.nextRecord();

        assertNotNull(record);
        assertEquals(1, parser.getRecordNumber());
        String[] values = record.values();
        assertArrayEquals(new String[] { "value1" }, values);
        assertEquals("comment line 1\ncomment line 2", record.getComment());
    }

    @Test
    void testNextRecord_withInvalidToken_throwsIOException() throws Exception {
        // Setup tokens: INVALID
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.INVALID;
            reusableToken.content = null;
            reusableToken.isReady = false;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        IOException thrown = assertThrows(IOException.class, () -> parser.nextRecord());
        assertTrue(thrown.getMessage().contains("invalid parse sequence"));
    }
}
